from openai_agents import Agent

class LoopProtectedAgent(Agent):
    def __init__(self, *args, max_handoffs=3, **kwargs):
        super().__init__(*args, **kwargs)
        self.handoff_counts = {}

    def handoff(self, target_agent):
        pair = (self.id, target_agent.id)
        self.handoff_counts[pair] = self.handoff_counts.get(pair, 0) + 1
        if self.handoff_counts[pair] > self.max_handoffs:
            return "Handoff limit exceeded - ending conversation"
        return super().handoff(target_agent)

from openai_agents import Guardrail

class InjectionGuard(Guardrail):
    def check(self, input_text):
        dangerous_patterns = [
            'ignore previous instructions',
            'you are now',
            'forget everything'
        ]
        for pattern in dangerous_patterns:
            if pattern in input_text.lower():
                return "Input blocked: suspicious instruction override detected"
        return input_text

from openai_agents import Tool
import json

class ValidatedTool(Tool):
    def __init__(self, func, output_schema):
        self.func = func
        self.schema = output_schema

    def execute(self, *args, **kwargs):
        result = self.func(*args, **kwargs)
        # Ensure valid JSON
        validated = {"result": result, "valid": True}
        return json.dumps(validated)
